mapper.select:
SELECT l.*, u.real_name AS owner_name,
       di.item_value AS source_channel_name
FROM crm_lead l
LEFT JOIN sys_user u ON l.owner_id = u.id
LEFT JOIN sys_dict_item di ON di.type_code = 'lead_source' AND di.item_code = l.source_channel AND di.deleted_at IS NULL

    l.deleted_at IS NULL

        AND (l.name LIKE '%' || #{keywords} || '%'
        OR l.phone LIKE '%' || #{keywords} || '%'
        OR l.company LIKE '%' || #{keywords} || '%')

    AND l.status = #{status}
    AND l.source_channel = #{sourceChannel}
    AND l.owner_id = #{ownerId}
    AND l.assign_type = #{assignType}
    AND l.province = #{province}
    AND l.city = #{city}
    AND l.industry = #{industry}
    AND l.created_at >= #{startDate}::timestamp
    AND l.created_at <= #{endDate}::timestamp
    AND l.pool_return_at IS NOT NULL
    AND l.pool_return_at IS NULL

ORDER BY l.created_at DESC
